// Track: French (France), for an English speaker. Built at full depth from
// the start (not a starter set — Italian taught us starter sets feel too
// thin against the mastery tracker). Categories: vocab (basics + classic
// false friends), gram (gendered articles, être/avoir auxiliary choice,
// required ne...pas negation, subjunctive trigger phrases, y/en pronouns —
// genuine trip-ups for English speakers), trad (idioms), and fono (liaison,
// nasal vowels, silent letters — the things that actually trip up English
// speakers reading French aloud).
// Parity pass 2026-07-10 (with the esForEn deepening): every French-language
// prompt now carries a promptNative English subtitle (bank slot 6), and the
// track gained C1 items plus its first C2 content (expletive ne, dont,
// passé simple recognition, l'ours/anguille proverbs) so all six CEFR tiers
// have ≥3 items for placement sampling. English-framed prompts (journée,
// manquer) deliberately have no subtitle — it would just duplicate them.

import { buildFrequencyBank } from "../../lib/frequencyVocab";
import WORDS from "../vocab/frWords";

const cap = (s) => s.charAt(0).toUpperCase() + s.slice(1);

// Word Bank prompt formulas for buildFrequencyBank (generator is language-neutral).
const FR_FORMULAS = {
  recognitionPrompt: (w) => `'${cap(w)}' signifie...`,
  recognitionNative: (w) => ({ en: `'${cap(w)}' means...` }),
  recognitionExplain: (w, g, noteEn) => ({
    en: `'${cap(w)}' means ${g}.${noteEn}`,
    es: `'${cap(w)}' significa ${g}.`,
  }),
  productionPrompt: (g) => `Comment dit-on '${g}' en français?`,
  productionNative: (g) => ({ en: `How do you say '${g}' in French?` }),
  productionExplain: (w, g, noteEn) => ({
    en: `'${g}' is '${w}'.${noteEn}`,
    es: `'${g}' se dice '${w}'.`,
  }),
};

import { THEMES, tagFor } from "./frForEnTags";

const CATS = {
  vocab: { label: "Vocabulaire", color: "#3DDBFF" },
  fvocab: { label: "Mots", color: "#7BE495" },
  verbo: { label: "Verbes", color: "#4DD599" },
  trad: { label: "Expressions", color: "#FF3D7F" },
  fono: { label: "Phonétique", color: "#B98EFF" },
};

